SELECT shared_with, share_date
FROM benchmark_shares
WHERE share_id = 0;

SELECT COUNT(*) AS private_shares
FROM benchmark_shares
WHERE share_type = 'private';

SELECT generate_date, COUNT(*) as report_count
FROM benchmark_reports
GROUP BY generate_date;

SELECT shared_with, share_type
FROM benchmark_shares
WHERE share_date = '2023-05-03';

SELECT version_number, release_date
FROM jvm_versions
WHERE vendor = 'Oracle';
